+/* Reset and base styles */
+* {
+    margin: 0;
+    padding: 0;
+    box-sizing: border-box;
+}
+
+:root {
+    --bg-translucent: rgba(22, 22, 26, 0.85);
+    --border-color: rgba(255, 255, 255, 0.08);
+    --text-primary: rgba(255, 255, 255, 0.95);
+    --text-secondary: rgba(255, 255, 255, 0.6);
+    --text-tertiary: rgba(255, 255, 255, 0.4);
+    --accent-gradient: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
+    --success-color: #4ade80;
+    --warning-color: #fbbf24;
+    --error-color: #f87171;
+    --input-bg: rgba(255, 255, 255, 0.08);
+    --input-bg-hover: rgba(255, 255, 255, 0.12);
+    --input-border: rgba(255, 255, 255, 0.15);
+    --input-border-focus: rgba(255, 255, 255, 0.3);
+}
+
+body {
+    background: transparent;
+    font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', 'SF Pro Text', system-ui, sans-serif;
+    color: var(--text-primary);
+    overflow: hidden;
+    height: 100vh;
+    width: 100vw;
+    -webkit-font-smoothing: antialiased;
+    -moz-osx-font-smoothing: grayscale;
+}
+
+/* Main container - grid layout */
+.container {
+    display: grid;
+    grid-template-rows: 52px 1fr 140px;
+    height: 100vh;
+    width: 100vw;
+}
+
+/* Top bar - translucent with blur */
+.top-bar {
+    background: var(--bg-translucent);
+    backdrop-filter: blur(24px) saturate(180%);
+    -webkit-backdrop-filter: blur(24px) saturate(180%);
+    display: flex;
+    align-items: center;
+    padding: 0 20px;
+    gap: 16px;
+    -webkit-app-region: drag;
+    border-bottom: 1px solid var(--border-color);
+}
+
+.top-bar > * {
+    -webkit-app-region: no-drag;
+}
+
+.logo {
+    display: flex;
+    align-items: center;
+    gap: 8px;
+    color: var(--text-primary);
+    font-weight: 600;
+    font-size: 15px;
+    -webkit-app-region: drag;
+}
+
+.logo svg {
+    opacity: 0.9;
+}
+
+/* Model selector dropdown */
+.model-selector {
+    background: var(--input-bg);
+    border: 1px solid var(--input-border);
+    border-radius: 8px;
+    padding: 8px 32px 8px 12px;
+    color: var(--text-primary);
+    font-size: 13px;
+    font-weight: 500;
+    cursor: pointer;
+    outline: none;
+    appearance: none;
+    -webkit-appearance: none;
+    background-image: url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1L5 5L9 1' stroke='rgba(255,255,255,0.5)' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E");
+    background-repeat: no-repeat;
+    background-position: right 12px center;
+    transition: background-color 0.15s, border-color 0.15s;
+}
+
+.model-selector:hover {
+    background-color: var(--input-bg-hover);
+    border-color: var(--input-border-focus);
+}
+
+.model-selector:focus {
+    border-color: var(--input-border-focus);
+}
+
+.model-selector option {
+    background: #1a1a1e;
+    color: white;
+    padding: 8px;
+}
+
+/* Action buttons group */
+.actions {
+    display: flex;
+    gap: 4px;
+}
+
+.action-button {
+    background: transparent;
+    border: 1px solid transparent;
+    border-radius: 8px;
+    padding: 8px;
+    color: var(--text-secondary);
+    cursor: pointer;
+    transition: all 0.15s;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.action-button:hover {
+    background: var(--input-bg);
+    color: var(--text-primary);
+    border-color: var(--input-border);
+}
+
+.action-button:active {
+    transform: scale(0.95);
+}
+
+/* Status indicator */
+.status-container {
+    display: flex;
+    align-items: center;
+    gap: 8px;
+    margin-left: auto;
+}
+
+.status-dot {
+    width: 8px;
+    height: 8px;
+    border-radius: 50%;
+    background: var(--success-color);
+    box-shadow: 0 0 8px var(--success-color);
+    transition: background-color 0.3s, box-shadow 0.3s;
+}
+
+.status-dot.thinking {
+    background: var(--warning-color);
+    box-shadow: 0 0 8px var(--warning-color);
+    animation: pulse 1.5s ease-in-out infinite;
+}
+
+.status-dot.error {
+    background: var(--error-color);
+    box-shadow: 0 0 8px var(--error-color);
+}
+
+@keyframes pulse {
+    0%, 100% { opacity: 1; }
+    50% { opacity: 0.5; }
+}
+
+.status {
+    font-size: 12px;
+    font-weight: 500;
+    color: var(--text-secondary);
+    text-transform: uppercase;
+    letter-spacing: 0.5px;
+}
+
+/* Terminal hole - transparent passthrough zone */
+.terminal-hole {
+    background: transparent;
+    pointer-events: none; /* CSS-level click passthrough */
+}
+
+/* Bottom panel - input area */
+.bottom-panel {
+    background: var(--bg-translucent);
+    backdrop-filter: blur(24px) saturate(180%);
+    -webkit-backdrop-filter: blur(24px) saturate(180%);
+    padding: 20px;
+    border-top: 1px solid var(--border-color);
+    display: flex;
+    flex-direction: column;
+    gap: 12px;
+}
+
+.prompt-container {
+    display: flex;
+    gap: 12px;
+    align-items: flex-end;
+}
+
+.prompt-input {
+    flex: 1;
+    background: var(--input-bg);
+    border: 1px solid var(--input-border);
+    border-radius: 16px;
+    padding: 16px 20px;
+    color: var(--text-primary);
+    font-size: 15px;
+    line-height: 1.5;
+    resize: none;
+    outline: none;
+    font-family: inherit;
+    transition: border-color 0.15s, background-color 0.15s, box-shadow 0.15s;
+}
+
+.prompt-input:focus {
+    border-color: var(--input-border-focus);
+    background: var(--input-bg-hover);
+    box-shadow: 0 0 0 4px rgba(102, 126, 234, 0.1);
+}
+
+.prompt-input::placeholder {
+    color: var(--text-tertiary);
+}
+
+.send-button {
+    background: var(--accent-gradient);
+    border: none;
+    border-radius: 14px;
+    width: 52px;
+    height: 52px;
+    color: white;
+    cursor: pointer;
+    transition: transform 0.1s, opacity 0.15s, box-shadow 0.15s;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    flex-shrink: 0;
+    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.3);
+}
+
+.send-button:hover {
+    transform: scale(1.05);
+    box-shadow: 0 6px 16px rgba(102, 126, 234, 0.4);
+}
+
+.send-button:active {
+    transform: scale(0.95);
+}
+
+.send-button:disabled {
+    opacity: 0.5;
+    cursor: not-allowed;
+    transform: none;
+}
+
+.send-button svg {
+    margin-left: 2px;
+}
+
+/* Keyboard hints */
+.prompt-hints {
+    display: flex;
+    gap: 16px;
+    padding: 0 4px;
+}
+
+.hint {
+    font-size: 11px;
+    color: var(--text-tertiary);
+    display: flex;
+    align-items: center;
+    gap: 4px;
+}
+
+.hint kbd {
+    background: var(--input-bg);
+    border: 1px solid var(--border-color);
+    border-radius: 4px;
+    padding: 2px 6px;
+    font-family: inherit;
+    font-size: 10px;
+}
+
+/* Responsive adjustments */
+@media (max-width: 600px) {
+    .top-bar {
+        padding: 0 12px;
+        gap: 8px;
+    }
+
+    .logo span {
+        display: none;
+    }
+
+    .bottom-panel {
+        padding: 16px;
+    }
+
+    .prompt-hints {
+        display: none;
+    }
+}

