+/**
+ * Zell Overlay JavaScript
+ *
+ * Handles communication between the WebKit overlay and Swift via WKScriptMessageHandler.
+ * The overlay provides rich UI while the Ghostty terminal handles actual LLM output.
+ */
+
+// ============================================================================
+// Hole Punch - Report transparent region bounds to Swift
+// ============================================================================
+
+function updateHoleRect() {
+    const hole = document.getElementById('terminalHole');
+    if (!hole) return;
+
+    const rect = hole.getBoundingClientRect();
+
+    // Send bounds to Swift for hitTest override
+    // Note: Y coordinate is flipped (Cocoa uses bottom-left origin)
+    window.webkit.messageHandlers.holePunch.postMessage({
+        x: rect.left,
+        y: window.innerHeight - rect.bottom,
+        width: rect.width,
+        height: rect.height
+    });
+}
+
+// Update on resize and initial load
+window.addEventListener('resize', updateHoleRect);
+window.addEventListener('load', updateHoleRect);
+
+// Also update after any layout changes
+const resizeObserver = new ResizeObserver(updateHoleRect);
+document.addEventListener('DOMContentLoaded', () => {
+    const hole = document.getElementById('terminalHole');
+    if (hole) resizeObserver.observe(hole);
+});
+
+// ============================================================================
+// Prompt Handling
+// ============================================================================
+
+function sendPrompt() {
+    const input = document.getElementById('promptInput');
+    const prompt = input.value.trim();
+
+    if (!prompt) return;
+
+    // Send to Swift
+    window.webkit.messageHandlers.prompt.postMessage({ prompt: prompt });
+
+    // Clear input and refocus
+    input.value = '';
+    input.focus();
+
+    // Update UI state
+    setThinking(true);
+}
+
+// Keyboard shortcuts
+document.addEventListener('keydown', (e) => {
+    const input = document.getElementById('promptInput');
+
+    // Cmd+Enter to send
+    if (e.metaKey && e.key === 'Enter') {
+        e.preventDefault();
+        sendPrompt();
+    }
+
+    // Cmd+K to clear terminal
+    if (e.metaKey && e.key === 'k') {
+        e.preventDefault();
+        clearTerminal();
+    }
+
+    // Focus input on any key if not already focused
+    if (!e.metaKey && !e.ctrlKey && !e.altKey &&
+        document.activeElement !== input &&
+        e.key.length === 1) {
+        input.focus();
+    }
+});
+
+// Auto-resize textarea
+document.addEventListener('DOMContentLoaded', () => {
+    const input = document.getElementById('promptInput');
+    if (!input) return;
+
+    input.addEventListener('input', () => {
+        // Reset height to recalculate
+        input.style.height = 'auto';
+        // Set new height based on content (max 4 lines)
+        const maxHeight = 4 * 24; // ~4 lines
+        input.style.height = Math.min(input.scrollHeight, maxHeight) + 'px';
+    });
+});
+
+// ============================================================================
+// Actions
+// ============================================================================
+
+function newChat() {
+    window.webkit.messageHandlers.action.postMessage({ action: 'newChat' });
+
+    // Clear input
+    const input = document.getElementById('promptInput');
+    if (input) {
+        input.value = '';
+        input.focus();
+    }
+}
+
+function clearTerminal() {
+    window.webkit.messageHandlers.action.postMessage({ action: 'clear' });
+}
+
+function openSettings() {
+    window.webkit.messageHandlers.action.postMessage({ action: 'settings' });
+}
+
+// ============================================================================
+// Model Selection
+// ============================================================================
+
+document.addEventListener('DOMContentLoaded', () => {
+    const select = document.getElementById('modelSelect');
+    if (!select) return;
+
+    select.addEventListener('change', (e) => {
+        window.webkit.messageHandlers.modelChange.postMessage({
+            model: e.target.value
+        });
+    });
+});
+
+// ============================================================================
+// Swift → JavaScript API
+// ============================================================================
+
+/**
+ * Update the status indicator
+ * @param {string} message - Status message (Ready, Thinking, Error, etc.)
+ */
+function updateStatus(message) {
+    const status = document.getElementById('status');
+    const dot = document.getElementById('statusDot');
+
+    if (status) {
+        status.textContent = message;
+    }
+
+    if (dot) {
+        dot.className = 'status-dot';
+        const lower = message.toLowerCase();
+        if (lower.includes('think') || lower.includes('processing')) {
+            dot.classList.add('thinking');
+        } else if (lower.includes('error') || lower.includes('fail')) {
+            dot.classList.add('error');
+        }
+    }
+
+    // Update send button state
+    setThinking(message.toLowerCase().includes('think'));
+}
+
+/**
+ * Set thinking state (disables send button)
+ * @param {boolean} thinking
+ */
+function setThinking(thinking) {
+    const button = document.getElementById('sendButton');
+    if (button) {
+        button.disabled = thinking;
+    }
+}
+
+/**
+ * Update the model dropdown options
+ * @param {string[]} models - Array of model names
+ */
+function updateModels(models) {
+    const select = document.getElementById('modelSelect');
+    if (!select || !Array.isArray(models)) return;
+
+    // Remember current selection
+    const current = select.value;
+
+    // Clear and repopulate
+    select.innerHTML = '';
+    models.forEach(model => {
+        const option = document.createElement('option');
+        option.value = model;
+        option.textContent = formatModelName(model);
+        select.appendChild(option);
+    });
+
+    // Restore selection if still available
+    if (models.includes(current)) {
+        select.value = current;
+    }
+}
+
+/**
+ * Format model name for display
+ * @param {string} name - Raw model name
+ * @returns {string} Formatted name
+ */
+function formatModelName(name) {
+    // Clean up common model name patterns
+    return name
+        .replace(/\.gguf$/i, '')
+        .replace(/-/g, ' ')
+        .replace(/_/g, ' ')
+        .split(' ')
+        .map(word => word.charAt(0).toUpperCase() + word.slice(1))
+        .join(' ');
+}
+
+/**
+ * Show a notification toast
+ * @param {string} message - Notification message
+ * @param {string} type - Notification type (info, success, error, warning)
+ */
+function showNotification(message, type = 'info') {
+    // Create notification element
+    const notification = document.createElement('div');
+    notification.className = `notification notification-${type}`;
+    notification.textContent = message;
+
+    // Add to DOM
+    document.body.appendChild(notification);
+
+    // Animate in
+    requestAnimationFrame(() => {
+        notification.classList.add('show');
+    });
+
+    // Remove after delay
+    setTimeout(() => {
+        notification.classList.remove('show');
+        setTimeout(() => notification.remove(), 300);
+    }, 3000);
+}
+
+// ============================================================================
+// Initialization
+// ============================================================================
+
+document.addEventListener('DOMContentLoaded', () => {
+    // Focus input on load
+    const input = document.getElementById('promptInput');
+    if (input) {
+        input.focus();
+    }
+
+    // Initial hole rect update
+    updateHoleRect();
+
+    console.log('Zell overlay initialized');
+});
